package il.co.dcd.composermapper.parser; import il.co.dcd.composermapper.model.ContextDef; import il.co.dcd.composermapper.util.XmlUtil; import org.w3c.dom.*; import java.nio.file.Path; import java.util.*;
public class ContextFileParser { public List<ContextDef> parse(Path xml){ List<ContextDef> out=new ArrayList<>(); walk(XmlUtil.parse(xml).getDocumentElement(), xml, out); return out; } private void walk(Element e, Path xml, List<ContextDef> out){ if("context".equals(e.getTagName())) out.add(parseCtx(e,xml)); for(Element c:XmlUtil.childElements(e)) walk(c,xml,out); } private ContextDef parseCtx(Element e, Path xml){ ContextDef c=new ContextDef(); c.setId(XmlUtil.attr(e,"id")); c.setParent(XmlUtil.attr(e,"parent")); c.setType(XmlUtil.attr(e,"type")); c.setSourceFile(xml); for(int i=0;i<e.getAttributes().getLength();i++){ var a=e.getAttributes().item(i); c.getRawAttributes().put(a.getNodeName(),a.getNodeValue()); } return c; } }
